import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate, Link } from 'react-router-dom';

function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('http://localhost:8000/api/token/', {
        username: username,
        password: password
      });
      localStorage.setItem('access', response.data.access);
      localStorage.setItem('refresh', response.data.refresh);
      localStorage.setItem('username', username);

    if (props.setIsAuthenticated) props.setIsAuthenticated(true);
    if (props.setUsername) props.setUsername(username);
      navigate('/');
    } catch (err) {
      setError('Неверное имя пользователя или пароль');
    }
  };

  return (
    <div style={{ 
      display: 'flex', 
      justifyContent: 'center', 
      alignItems: 'center', 
      minHeight: '80vh'
    }}>
      <form onSubmit={handleSubmit} style={{
        backgroundColor: '#1a1a1a',
        padding: 40,
        borderRadius: 12,
        width: 400
      }}>
        <h2 style={{ color: 'white', marginBottom: 20, textAlign: 'center' }}>Вход</h2>
        {error && <p style={{ color: '#ff4444', marginBottom: 15, textAlign: 'center' }}>{error}</p>}
        <input
          type="text"
          placeholder="Имя пользователя"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          style={{
            width: '100%',
            padding: 12,
            marginBottom: 15,
            backgroundColor: '#272727',
            border: 'none',
            borderRadius: 8,
            color: 'white'
          }}
        />
        <input
          type="password"
          placeholder="Пароль"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          style={{
            width: '100%',
            padding: 12,
            marginBottom: 20,
            backgroundColor: '#272727',
            border: 'none',
            borderRadius: 8,
            color: 'white'
          }}
        />
        <button type="submit" style={{
          width: '100%',
          padding: 12,
          backgroundColor: '#ff0000',
          color: 'white',
          border: 'none',
          borderRadius: 8,
          fontSize: 16,
          cursor: 'pointer'
        }}>
          Войти
        </button>
        <p style={{ color: '#aaa', textAlign: 'center', marginTop: 20 }}>
          Нет аккаунта? <Link to="/register" style={{ color: '#ff0000' }}>Зарегистрируйтесь</Link>
        </p>
      </form>
    </div>
  );
}

export default LoginPage;
